   587→// Helper: Complete assessment
   588→async function completeAssessment(client, sessionId, userId) {
   589→  const sessionResult = await client.query(
   590→    'SELECT * FROM assessment_sessions WHERE id = $1',
   591→    [sessionId]
   592→  );
   593→  const session = sessionResult.rows[0];
   594→
   595→  // Get skill name for the title
   596→  const skillResult = await client.query(
   597→    'SELECT skill_name FROM candidate_skills WHERE id = $1',
   598→    [session.skill_id]
   599→  );
   600→  const skillName = skillResult.rows.length > 0 ? skillResult.rows[0].skill_name : 'Unknown';
   601→
   602→  // Calculate anti-cheat score (100 = clean, lower = suspicious)
   603→  let antiCheatScore = 100;
   604→  antiCheatScore -= (session.tab_switches || 0) * 5;
   605→  antiCheatScore -= (session.copy_paste_attempts || 0) * 10;
   606→  antiCheatScore -= (session.time_anomalies || 0) * 5;
   607→  antiCheatScore = Math.max(0, antiCheatScore);
   608→
   609→  const passed = (session.score || 0) >= 60 && antiCheatScore >= 50;
   610→
   611→  // Mark session complete
   612→  await client.query(
   613→    "UPDATE assessment_sessions SET status = 'completed', completed_at = NOW() WHERE id = $1",
   614→    [sessionId]
   615→  );
   616→
   617→  // Create skill assessment record
   618→  const assessmentResult = await client.query(`
   619→    INSERT INTO skill_assessments
   620→    (user_id, skill_id, session_id, assessment_type, title, score, max_score, passed,
   621→     anti_cheat_score, behavioral_flags, duration_seconds, started_at, completed_at)
   622→    VALUES ($1, $2, $3, 'dynamic', $4, $5, 100, $6, $7, $8,
   623→            EXTRACT(EPOCH FROM (NOW() - $9::timestamp)), $9, NOW())
   624→    RETURNING id
   625→  `, [
   626→    userId,
   627→    session.skill_id,
   628→    sessionId,
   629→    `${skillName} Assessment`,
   630→    session.score || 0,
   631→    passed,
   632→    antiCheatScore,
   633→    JSON.stringify({
   634→      tab_switches: session.tab_switches || 0,
   635→      copy_paste: session.copy_paste_attempts || 0,
   636→      time_anomalies: session.time_anomalies || 0,
   637→      max_difficulty: session.max_difficulty_reached || 2
   638→    }),
   639→    session.started_at
   640→  ]);
   641→
   642→  // If passed, mark skill as verified
   643→  if (passed) {
   644→    await client.query(
   645→      'UPDATE candidate_skills SET is_verified = true, verified_at = NOW(), verified_score = $1 WHERE id = $2',
   646→      [session.score, session.skill_id]
   647→    );
   648→  }
   649→
   650→  // Event-driven: Feed assessment score into OmniScore technical component
   651→  try {
   652→    await omniscoreService.addTechnicalComponent(userId, assessmentResult.rows[0].id, session.score || 0, 100);
   653→    console.log(`[OmniScore] Assessment ${assessmentResult.rows[0].id} fed into OmniScore for user ${userId} (score: ${session.score})`);
   654→  } catch (err) {
   655→    console.error('[OmniScore] Failed to update from assessment:', err.message);
   656→  }
   657→
   658→  return assessmentResult.rows[0].id;
   659→}
