   704→      });
   705→    }
   706→
   707→    if (session.status === 'in_progress') {
   708→      // Find the last question that was asked
   709→      const questionsAsked = typeof session.questions_asked === 'string'
   710→        ? JSON.parse(session.questions_asked) : (session.questions_asked || []);
   711→      const answersGiven = typeof session.answers_given === 'string'
