   732→              timeLimit: q.time_limit_seconds || 120,
   733→              questionNumber: session.current_question_index || questionsAsked.length,
   734→              totalQuestions: 10,
   735→            },
   736→          });
   737→        }
   738→      }
   739→
   740→      // All questions answered but session not completed - might need to generate next
   741→      // For now, return the state so client can handle
   742→      return res.json({
   743→        status: 'in_progress',
   744→        skillName,
   745→        currentQuestionIndex: session.current_question_index || 0,
   746→      });
   747→    }
   748→
   749→    // Abandoned or other status
   750→    return res.json({ status: session.status, skillName });
   751→
