    res.json({
      assessment: {
        ...assessment,
        detailedAnswers,
      },
    });
  } catch (error) {
    console.error('Error fetching assessment detail:', error);
    res.status(500).json({ error: 'Failed to fetch assessment detail' });
  }
});

