   607→// Analyze speech transcription for communication quality
   608→function analyzeSpeechPatterns(transcription, durationSeconds) {
   609→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   610→  const wordCount = words.length;
   611→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   612→
   613→  // Filler word detection
   614→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   615→  const fillerCounts = {};
   616→  let totalFillers = 0;
   617→  const lowerTranscription = transcription.toLowerCase();
   618→
   619→  for (const filler of fillerWords) {
   620→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   621→    const matches = lowerTranscription.match(regex);
   622→    if (matches && matches.length > 0) {
   623→      fillerCounts[filler] = matches.length;
   624→      totalFillers += matches.length;
   625→    }
   626→  }
   627→
   628→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   629→
   630→  // Pace analysis
   631→  let paceAssessment = 'good';
   632→  let paceFeedback = '';
   633→  if (wpm < 100) {
   634→    paceAssessment = 'too_slow';
   635→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   636→  } else if (wpm < 120) {
   637→    paceAssessment = 'slightly_slow';
   638→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   639→  } else if (wpm <= 160) {
   640→    paceAssessment = 'good';
   641→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   642→  } else if (wpm <= 180) {
   643→    paceAssessment = 'slightly_fast';
   644→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   645→  } else {
   646→    paceAssessment = 'too_fast';
   647→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   648→  }
   649→
   650→  // Sentence structure analysis
   651→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   652→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   653→
   654→  // Communication score (1-10)
   655→  let communicationScore = 7;
   656→  // Penalize for filler words
   657→  if (fillerRate > 5) communicationScore -= 2;
   658→  else if (fillerRate > 3) communicationScore -= 1;
   659→  // Penalize for bad pace
   660→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   661→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   662→  // Reward for good sentence structure
   663→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   664→  // Penalize for very short responses
   665→  if (wordCount < 50) communicationScore -= 2;
   666→  else if (wordCount < 100) communicationScore -= 1;
   667→  // Reward for substantial responses
   668→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   669→
   670→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   671→
   672→  return {
   673→    word_count: wordCount,
   674→    duration_seconds: durationSeconds,
   675→    words_per_minute: wpm,
   676→    filler_words: fillerCounts,
   677→    total_fillers: totalFillers,
   678→    filler_rate: Math.round(fillerRate * 10) / 10,
   679→    pace: {
   680→      assessment: paceAssessment,
   681→      wpm,
   682→      feedback: paceFeedback
   683→    },
   684→    sentence_count: sentences.length,
   685→    avg_sentence_length: avgSentenceLength,
   686→    communication_score: communicationScore,
   687→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   688→  };
   689→}
   690→
   691→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   692→  const tips = [];
   693→
   694→  if (fillerRate > 3) {
   695→    const topFillers = Object.entries(fillerCounts)
   696→      .sort((a, b) => b[1] - a[1])
   697→      .slice(0, 3)
   698→      .map(([word, count]) => `"${word}" (${count}x)`);
   699→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   700→  }
   701→
   702→  if (wpm > 160) {
   703→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   704→  } else if (wpm < 110) {
   705→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   706→  }
   707→
   708→  if (wordCount < 80) {
   709→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   710→  }
   711→
   712→  if (tips.length === 0) {
   713→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   714→  }
   715→
   716→  return tips;
   717→}
