   804→// Comprehensive video interview analysis combining all signals
   805→async function analyzeVideoInterviewResponse(question, transcription, frames, durationSeconds, keyPoints, options = {}) {
   806→  const audioData = options.audioData || null;
   807→  let finalTranscription = transcription;
   808→
   809→  // Step 1: If audio data available, try Whisper for more accurate transcription
   810→  let whisperResult = null;
   811→  if (audioData) {
   812→    try {
   813→      console.log('[ai] Transcribing audio with Whisper...');
   814→      whisperResult = await transcribeAudioWithWhisper(audioData, options);
   815→      if (whisperResult && whisperResult.text && whisperResult.text.trim().length > 20) {
   816→        finalTranscription = whisperResult.text;
   817→        console.log(`[ai] Whisper transcription: ${finalTranscription.length} chars (replaced browser transcription)`);
   818→      } else {
   819→        console.log('[ai] Whisper result too short, keeping browser transcription');
   820→      }
   821→    } catch (err) {
   822→      console.warn('[ai] Whisper failed, using browser transcription:', err.message);
   823→    }
   824→  }
   825→
   826→  // Step 2: Run all analyses in parallel
   827→  const analysisPromises = [
   828→    analyzeInterviewResponse(question, finalTranscription, keyPoints, options),
   829→    generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options),
   830→    analyzeVideoPresentation(frames, options)
   831→  ];
   832→
   833→  // Add voice quality analysis if we have audio
   834→  if (audioData) {
   835→    analysisPromises.push(analyzeVoiceQuality(finalTranscription, durationSeconds, options));
   836→  }
   837→
   838→  const results = await Promise.all(analysisPromises);
   839→  const [contentAnalysis, contentCoaching, videoAnalysis] = results;
   840→  const voiceAnalysis = audioData ? results[3] : null;
   841→
   842→  // Algorithmic speech analysis
   843→  const speechAnalysis = analyzeSpeechPatterns(finalTranscription, durationSeconds);
   844→
   845→  // Calculate category scores
   846→  const contentScore = contentAnalysis.score || 5;
   847→  let communicationScore = speechAnalysis.communication_score || 5;
   848→  const presentationScore = videoAnalysis.overall_presentation || 5;
   849→
   850→  // If voice analysis available, blend its score into communication
   851→  if (voiceAnalysis && voiceAnalysis.overall_voice_score) {
