   856→    communicationScore = Math.max(1, Math.min(10, communicationScore));
   857→  }
   858→
   859→  // Weighted overall score
   860→  const overallScore = Math.round(
   861→    (contentScore * 0.45 + communicationScore * 0.25 + presentationScore * 0.30) * 10
   862→  ) / 10;
   863→
   864→  return {
   865→    overall_score: overallScore,
   866→
   867→    // Category breakdowns
   868→    content: {
