  1023→// Generate session-end feedback for a mock interview
  1024→// Returns structured format matching practice interview: content + communication + presentation
  1025→async function generateSessionFeedback(conversation, targetRole, options = {}) {
  1026→  const convoText = conversation.map(turn => {
  1027→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
  1028→    return `CANDIDATE: ${turn.text}`;
  1029→  }).join('\n\n');
  1030→
  1031→  // Calculate basic metrics from the text
  1032→  const candidateTurns = conversation.filter(t => t.role === 'candidate');
  1033→  const allCandidateText = candidateTurns.map(t => t.text).join(' ');
  1034→  const wordCount = allCandidateText.split(/\s+/).filter(w => w).length;
  1035→  const questionCount = conversation.filter(t => t.role === 'interviewer').length;
  1036→
  1037→  // Estimate duration from timestamps
  1038→  let durationSeconds = 0;
  1039→  if (conversation.length >= 2) {
  1040→    const first = new Date(conversation[0].timestamp || Date.now());
  1041→    const last = new Date(conversation[conversation.length - 1].timestamp || Date.now());
  1042→    durationSeconds = Math.max(60, Math.round((last - first) / 1000));
  1043→  }
  1044→  const wpm = durationSeconds > 0 ? Math.round(wordCount / (durationSeconds / 60)) : 120;
  1045→
  1046→  const prompt = `You just completed a mock interview for a "${targetRole}" position. Review the full conversation and provide structured feedback in THREE sections matching our coaching format.
  1047→
  1048→FULL INTERVIEW TRANSCRIPT:
