  1068→    "covered_points": ["Key competency they demonstrated well"],
  1069→    "missed_points": ["Important area they didn't address or was weak"],
  1070→    "detailed_feedback": "2-3 paragraph deep analysis of their answer quality across ALL questions. Reference patterns: did they improve? Were some topics stronger? Did follow-ups reveal depth or gaps?",
  1071→    "specific_tips": ["Actionable tip 1", "Actionable tip 2", "Actionable tip 3"],
  1072→    "common_mistake": "The most common interview mistake they exhibited",
  1073→    "star_method_usage": { "score": 1-10, "feedback": "How well they structured answers with Situation-Task-Action-Result" },
  1074→    "technical_depth": { "score": 1-10, "feedback": "Depth of technical knowledge and specificity" }
  1075→  },
  1076→
  1077→  "communication": {
  1078→    "score": 1-10,
  1079→    "word_count": ${wordCount},
  1080→    "words_per_minute": ${wpm},
  1081→    "duration_seconds": ${durationSeconds},
  1082→    "filler_words": {"um": 0, "uh": 0, "like": 0, "you know": 0, "so": 0, "basically": 0},
  1083→    "total_fillers": 0,
  1084→    "filler_rate": 0.0,
  1085→    "pace": {
