  1089→    },
  1090→    "tips": ["Speech improvement tip 1", "Tip 2"],
  1091→    "trends": "Did their communication improve/decline over the interview? More confident later? More filler words when nervous?"
  1092→  },
  1093→
  1094→  "question_scores": [
