  1165→// ─── TTS: Now with automatic fallback + database caching ─────
  1166→// Fallback chain: Cache → OpenAI TTS → null (browser Web Speech API fallback)
  1167→async function textToSpeech(text, options = {}) {
  1168→  const pool = require('./db');
  1169→  const crypto = require('crypto');
  1170→
  1171→  try {
  1172→    const voice = options.voice || 'nova';
  1173→    const speed = options.speed || 1.0;
  1174→
  1175→    // Truncate text to ~4000 chars (TTS API limit is 4096)
  1176→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
  1177→
  1178→    // Generate cache key from text + voice
  1179→    const cacheKey = crypto.createHash('sha256').update(`${voice}:${truncatedText}`).digest('hex');
  1180→
  1181→    // Check cache first — serves audio even when daily token limit is exhausted
  1182→    try {
  1183→      const cached = await pool.query(
  1184→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1185→        [cacheKey]
  1186→      );
  1187→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1188→        const buf = Buffer.from(cached.rows[0].audio_data);
  1189→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1190→        return buf;
  1191→      }
  1192→    } catch (cacheErr) {
  1193→      // Cache miss or table doesn't exist yet — continue to API
  1194→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1195→    }
  1196→
  1197→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1198→
  1199→    // Use provider service with automatic fallback
  1200→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1201→      voice,
  1202→      speed,
  1203→      subscriptionId: options.subscriptionId,
  1204→      module: 'mock_interview', feature: 'tts',
  1205→    });
  1206→
  1207→    if (!buf) {
  1208→      console.log('[tts] All providers failed, returning null for browser fallback');
  1209→      return null;
  1210→    }
  1211→
  1212→    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
  1213→
  1214→    // Cache the audio for future use (non-blocking)
  1215→    if (buf.length > 100) {
  1216→      pool.query(
  1217→        `INSERT INTO tts_cache (text_hash, voice, audio_data, text_preview)
  1218→         VALUES ($1, $2, $3, $4)
  1219→         ON CONFLICT (text_hash) DO NOTHING`,
  1220→        [cacheKey, voice, buf, truncatedText.substring(0, 100)]
  1221→      ).then(() => {
  1222→        console.log(`[tts] Cached audio for: "${truncatedText.substring(0, 50)}..."`);
  1223→      }).catch(err => {
  1224→        // Non-fatal — caching failure doesn't break TTS
  1225→        console.warn(`[tts] Cache write failed: ${err.message}`);
  1226→      });
  1227→    }
  1228→
  1229→    return buf;
  1230→  } catch (err) {
  1231→    console.error('[tts] Error:', err.message || err);
  1232→    return null;
  1233→  }
  1234→}
