    "duration_seconds": ${durationSeconds},
    "filler_words": {"um": 0, "uh": 0, "like": 0, "you know": 0, "so": 0, "basically": 0},
    "total_fillers": 0,
    "filler_rate": 0.0,
    "pace": {
      "assessment": "good|slightly_fast|slightly_slow|too_fast|too_slow",
